import React from 'react'
import Loader from 'react-loader-spinner'

export default () => {
    return (
        <Loader
            type="ThreeDots"
            color="#007bff"
            height={50}
            width={100}
            timeout={3000} //3 secs

        />
        /*<h5>Loading...</h5>*/
    )
}
